// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertInstanceOf;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.io.InputStream;
import java.util.Map;
import java.util.Set;

import org.eclipse.rdf4j.model.Model;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.Projection;
import org.eclipse.rdf4j.query.algebra.ProjectionElem;
import org.eclipse.rdf4j.query.algebra.ProjectionElemList;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.equivalence.AlgebraEquivalenceChecker;
import org.eclipse.rdf4j.query.algebra.equivalence.CheckOptions;
import org.eclipse.rdf4j.query.algebra.equivalence.Counterexample;
import org.eclipse.rdf4j.query.algebra.equivalence.EquivalenceResult;
import org.eclipse.rdf4j.query.algebra.equivalence.EquivalenceStatus;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationCase;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationOutcome;
import org.eclipse.rdf4j.query.algebra.equivalence.ObservationMode;
import org.eclipse.rdf4j.query.algebra.json.TupleExprJsonParser;
import org.eclipse.rdf4j.rio.RDFFormat;
import org.eclipse.rdf4j.rio.Rio;
import org.junit.jupiter.api.Test;

/**
 * Soundness regressions for former false-{@code EQUIVALENT} verdicts. Each test parses the original tuple expression
 * from a JSON resource, derives the transformed tree with a join-commutation transformer, evaluates both against a
 * bundled dataset that distinguishes them, and asserts the checker now refuses the commutation and returns
 * {@code NOT_EQUIVALENT} with a verified {@link Counterexample}. {@link IncomingBindingAnalyzer} used to make these
 * pairs prove {@code EQUIVALENT}: it neither collected variables read by a
 * {@link org.eclipse.rdf4j.query.algebra.LeftJoin} condition nor modelled re-binding writes performed by an
 * {@link org.eclipse.rdf4j.query.algebra.Extension}.
 */
class JsonTupleExprSoundnessRegressionTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String RESOURCE_ROOT = "/org/eclipse/rdf4j/query/algebra/equivalence/internal/";

	/**
	 * The LeftJoin condition {@code ?x > 5} reads {@code ?x} bound by the sibling join operand. Because {@code ?x} is a
	 * may-bind name of the LeftJoin's left arg (second Union branch), RDF4J's well-designed-left-join check exposes the
	 * sibling's binding to the condition at runtime, so join order is observable and the analyzer must count the
	 * condition's unsatisfied reads as incoming reads.
	 */
	@Test
	void leftJoinConditionReadBlocksJoinCommutation() throws Exception {
		TupleExpr original = parseTupleExpr("leftjoin-condition-blind-spot.json");
		TupleExpr transformed = commuteTopLevelJoin(original);
		EvaluationCase dataset = parseDataset("leftjoin-condition-blind-spot.nt",
				"left join condition reads sibling join binding");

		EvaluationOutcome originalOutcome = evaluate(original, dataset);
		EvaluationOutcome transformedOutcome = evaluate(transformed, dataset);

		// Original order: the condition sees ?x=10 from the sibling operand, holds, and binds ?c.
		assertEquals(1, originalOutcome.getSequence().size(), originalOutcome::toString);
		Map<String, Value> originalBindings = originalOutcome.getSequence().get(0).getBindings();
		assertEquals(Set.of("s", "x", "a", "b", "c"), originalBindings.keySet(), originalOutcome::toString);
		assertEquals(VF.createIRI("urn:counterexample:c1"), originalBindings.get("c"), originalOutcome::toString);

		// Commuted order: the LeftJoin is evaluated first, ?x is unbound, the condition errors to false, ?c stays
		// unbound.
		assertEquals(1, transformedOutcome.getSequence().size(), transformedOutcome::toString);
		Map<String, Value> transformedBindings = transformedOutcome.getSequence().get(0).getBindings();
		assertEquals(Set.of("s", "x", "a", "b"), transformedBindings.keySet(), transformedOutcome::toString);

		assertFalse(originalOutcome.sameAs(transformedOutcome, ObservationMode.BAG),
				() -> "expected meaningfully different results: " + originalOutcome + " versus " + transformedOutcome);

		CheckOptions options = checkOptions(dataset);
		assertDatasetIsVerifiedWitness(options, original, transformed);
		assertNotEquivalentWithVerifiedCounterexample(options, original, transformed);
	}

	/**
	 * The Extension re-binds {@code ?x}, a variable the sibling join operand also binds. {@code ExtensionIterator}
	 * overwrites incoming bindings, so join order decides whether the statement pattern is probed with the data value
	 * or with the overwritten constant — the analyzer must treat written names that overlap a sibling's may-bind set as
	 * order-observable. The difference is visible even under {@code ASK}: one row versus none.
	 */
	@Test
	void extensionOverwriteBlocksJoinCommutation() throws Exception {
		TupleExpr original = parseTupleExpr("extension-overwrite-blind-spot.json");
		TupleExpr transformed = commuteTopLevelJoin(original);
		EvaluationCase dataset = parseDataset("extension-overwrite-blind-spot.nt",
				"extension overwrites sibling join binding");

		EvaluationOutcome originalOutcome = evaluate(original, dataset);
		EvaluationOutcome transformedOutcome = evaluate(transformed, dataset);

		// Original order: the statement pattern binds ?x=1, then the Extension clobbers it with "overwritten".
		assertEquals(1, originalOutcome.getSequence().size(), originalOutcome::toString);
		Map<String, Value> originalBindings = originalOutcome.getSequence().get(0).getBindings();
		assertEquals(
				Map.of(
						"s", VF.createIRI("urn:counterexample:s1"),
						"x", VF.createLiteral("overwritten")),
				originalBindings,
				originalOutcome::toString);

		// Commuted order: ?x="overwritten" is pushed into the statement pattern, which matches nothing.
		assertEquals(0, transformedOutcome.getSequence().size(), transformedOutcome::toString);

		assertFalse(originalOutcome.sameAs(transformedOutcome, ObservationMode.BAG));
		assertFalse(originalOutcome.sameAs(transformedOutcome, ObservationMode.ASK),
				() -> "one row versus none must differ even under ASK: " + originalOutcome + " versus "
						+ transformedOutcome);

		CheckOptions options = checkOptions(dataset);
		assertDatasetIsVerifiedWitness(options, original, transformed);
		assertNotEquivalentWithVerifiedCounterexample(options, original, transformed);
	}

	/**
	 * Ancestors OUTSIDE the compared expressions must not influence the verdict: the same join pair used to flip from
	 * NOT_EQUIVALENT (detached) to EQUIVALENT when still attached under a live outer Projection, because the
	 * binding-discard walk escaped the analyzed root.
	 */
	@Test
	void ambientParentsOutsideTheComparedTreesDoNotChangeTheVerdict() throws Exception {
		TupleExpr original = parseTupleExpr("join-projection-drops-bindings.json");
		TupleExpr transformed = commuteTopLevelJoin(original);
		EvaluationCase dataset = parseDataset("join-projection-drops-bindings.nt",
				"projection drops inherited JOIN bindings");
		// Attach BOTH compared joins under outer Projections that are NOT part of the check; the
		// wrappers only exist to give the joins live parent chains (one detached side alone would
		// already diverge structurally and mask the defect).
		new Projection(original, new ProjectionElemList(new ProjectionElem("label")), false);
		new Projection(transformed, new ProjectionElemList(new ProjectionElem("label")), false);

		CheckOptions options = checkOptions(dataset);
		assertDatasetIsVerifiedWitness(options, original, transformed);
		assertNotEquivalentWithVerifiedCounterexample(options, original, transformed);
	}

	private static CheckOptions checkOptions(EvaluationCase dataset) {
		return CheckOptions.builder()
				.observationMode(ObservationMode.BAG)
				.boundedCounterexampleSearch(false)
				.addEvaluationCase(dataset)
				.build();
	}

	private static void assertDatasetIsVerifiedWitness(CheckOptions options, TupleExpr original,
			TupleExpr transformed) {
		BoundedCounterexampleFinder.SearchResult search = new BoundedCounterexampleFinder(options)
				.find(original, transformed);
		assertTrue(
				search.getCounterexample().isPresent(),
				() -> "the bundled dataset should be a verified witness of non-equivalence: " + search.getReason());
	}

	private static void assertNotEquivalentWithVerifiedCounterexample(CheckOptions options, TupleExpr original,
			TupleExpr transformed) {
		EquivalenceResult result = new AlgebraEquivalenceChecker(options).check(original, transformed);

		assertEquals(EquivalenceStatus.NOT_EQUIVALENT, result.getStatus(), result::getReason);
		assertInstanceOf(Counterexample.class, result.getEvidence().orElseThrow());
	}

	private static TupleExpr commuteTopLevelJoin(TupleExpr expression) {
		Join transformed = assertInstanceOf(Join.class, expression.clone());
		TupleExpr oldLeft = transformed.getLeftArg();
		transformed.setLeftArg(transformed.getRightArg());
		transformed.setRightArg(oldLeft);
		return transformed;
	}

	private static TupleExpr parseTupleExpr(String resourceName) throws IOException {
		try (InputStream input = resource(resourceName)) {
			return new TupleExprJsonParser().parse(input);
		}
	}

	private static EvaluationCase parseDataset(String resourceName, String label) throws IOException {
		try (InputStream input = resource(resourceName)) {
			Model model = Rio.parse(input, "", RDFFormat.NTRIPLES);
			return EvaluationCase.builder(label)
					.statements(model)
					.build();
		}
	}

	private static InputStream resource(String resourceName) {
		InputStream input = JsonTupleExprSoundnessRegressionTest.class
				.getResourceAsStream(RESOURCE_ROOT + resourceName);
		if (input == null) {
			throw new IllegalArgumentException("Missing test resource: " + resourceName);
		}
		return input;
	}

	private static EvaluationOutcome evaluate(TupleExpr expression, EvaluationCase dataset) {
		EvaluationAttempt attempt = new Rdf4jEvaluator().evaluate(expression, dataset, 10);
		assertTrue(attempt.isComplete(), attempt::getIncompleteReason);
		EvaluationOutcome outcome = attempt.getOutcome().orElseThrow();
		assertFalse(outcome.hasError(), outcome::toString);
		return outcome;
	}
}
